/// <summary>
/// Workflow document for the <c>ConDemoWfRequest</c> table.
/// </summary>
public class ConDemoWfRequestDocument extends WorkflowDocument
{
}

Method.Source:
/// <summary>
/// Returns the name of the query that supplies the workflow condition fields.
/// </summary>
/// <returns>The name of the query in the AOT.</returns>
public queryName getQueryName()
{
    return queryStr(ConDemoWfRequestQuery);
}

/// <summary>
/// Returns a <c>QueryRun</c> restricted to the record of the supplied workflow context.
/// </summary>
/// <param name = "_context">The workflow context of the running workflow instance.</param>
/// <returns>A <c>QueryRun</c> object.</returns>
public QueryRun getQueryRun(WorkflowContext _context)
{
    Query    query = new Query(queryStr(ConDemoWfRequestQuery));
    QueryRun queryRun = new QueryRun(query);

    queryRun.query().dataSourceTable(tableNum(ConDemoWfRequest)).addRange(fieldNum(ConDemoWfRequest, RecId)).value(SysQuery::value(_context.parmRecId()));

    return queryRun;
}
